import{_ as t,c as s,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Контекст: внедрение | opencode-supermemory","description":"Изучите внедрение контекста opencode-supermemory. Agent получает профиль и знания о проекте в начале сессии. Управляйте памятью через ключевые слова.","frontmatter":{"title":"Контекст: внедрение | opencode-supermemory","sidebarTitle":"Внедрение","subtitle":"Контекст: внедрение | opencode-supermemory","description":"Изучите внедрение контекста opencode-supermemory. Agent получает профиль и знания о проекте в начале сессии. Управляйте памятью через ключевые слова.","tags":["Контекст","Внедрение","prompt","Память"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"ru/supermemoryai/opencode-supermemory/core/context-injection/index.md","filePath":"ru/supermemoryai/opencode-supermemory/core/context-injection/index.md"}'),n={name:"ru/supermemoryai/opencode-supermemory/core/context-injection/index.md"};function i(r,e,l,p,d,c){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="механизм-автоматического-внедрения-контекста-позвольте-agent-предвидеть" tabindex="-1">Механизм автоматического внедрения контекста: позвольте Agent &quot;предвидеть&quot; <a class="header-anchor" href="#механизм-автоматического-внедрения-контекста-позвольте-agent-предвидеть" aria-label="Permalink to &quot;Механизм автоматического внедрения контекста: позвольте Agent &quot;предвидеть&quot;&quot;">​</a></h1><h2 id="что-вы-сможете-сделать-после-изучения" tabindex="-1">Что вы сможете сделать после изучения <a class="header-anchor" href="#что-вы-сможете-сделать-после-изучения" aria-label="Permalink to &quot;Что вы сможете сделать после изучения&quot;">​</a></h2><p>После изучения этого урока вы сможете:</p><ol><li><strong>Понять</strong>, почему Agent с самого начала знает ваши привычки кодирования и архитектуру проекта.</li><li><strong>Освоить</strong> &quot;трехмерную модель&quot; внедрения контекста (профиль пользователя, знания о проекте, релевантная память).</li><li><strong>Научиться</strong> использовать ключевые слова (например, &quot;Remember this&quot;) для активного вмешательства в поведение запоминания Agent.</li><li><strong>Настроить</strong> количество внедряемых элементов, балансируя длину контекста и информативность.</li></ol><hr><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>До появления плагина памяти в каждой новой сессии Agent был чистым листом. Вам приходилось повторять: &quot;я использую TypeScript&quot;, &quot;в этом проекте используется Next.js&quot;.</p><p><strong>Внедрение контекста (Context Injection)</strong> решает эту проблему. Это как бы вставка &quot;сводки задач&quot; в мозг Agent в момент его пробуждения.</p><h3 id="момент-триггера" tabindex="-1">Момент триггера <a class="header-anchor" href="#момент-триггера" aria-label="Permalink to &quot;Момент триггера&quot;">​</a></h3><p>opencode-supermemory очень сдержан и автоматически внедряется только при <strong>первом сообщении сессии</strong>.</p><ul><li><strong>Почему первое сообщение?</strong> Потому что это ключевой момент для определения тона сессии.</li><li><strong>А последующие сообщения?</strong> В последующие сообщения внедрение не происходит автоматически, чтобы не мешать потоку диалога, если вы не вызываете его активно (см. ниже &quot;Триггеризация по ключевым словам&quot;).</li></ul><h3 id="трехмерная-модель-внедрения" tabindex="-1">Трехмерная модель внедрения <a class="header-anchor" href="#трехмерная-модель-внедрения" aria-label="Permalink to &quot;Трехмерная модель внедрения&quot;">​</a></h3><p>Плагин параллельно получает три типа данных, объединяя их в блок подсказки <code>[SUPERMEMORY]</code>:</p><table tabindex="0"><thead><tr><th>Измерение данных</th><th>Источник</th><th>Функция</th><th>Пример</th></tr></thead><tbody><tr><td><strong>1. Профиль пользователя</strong> (Profile)</td><td><code>getProfile</code></td><td>Ваши долгосрочные предпочтения</td><td>&quot;Пользователь предпочитает функциональное программирование&quot;, &quot;предпочитает стрелочные функции&quot;</td></tr><tr><td><strong>2. Знания о проекте</strong> (Project)</td><td><code>listMemories</code></td><td>Глобальные знания о текущем проекте</td><td>&quot;В этом проекте используется Clean Architecture&quot;, &quot;API находится в src/api&quot;</td></tr><tr><td><strong>3. Релевантная память</strong> (Relevant)</td><td><code>searchMemories</code></td><td>Предыдущий опыт, релевантный вашему первому предложению</td><td>Вы спрашиваете &quot;как исправить этот баг&quot;, он ищет предыдущие аналогичные записи о исправлении</td></tr></tbody></table><hr><h2 id="что-внедряется" tabindex="-1">Что внедряется? <a class="header-anchor" href="#что-внедряется" aria-label="Permalink to &quot;Что внедряется?&quot;">​</a></h2><p>Когда вы отправляете первое сообщение в OpenCode, плагин незаметно вставляет следующее содержимое в System Prompt.</p><details class="details custom-block"><summary>Нажмите, чтобы просмотреть реальную структуру внедренного содержимого</summary><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[SUPERMEMORY]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User Profile:</span></span>
<span class="line"><span>- User prefers concise responses</span></span>
<span class="line"><span>- User uses Zod for all validations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Recent Context:</span></span>
<span class="line"><span>- Working on auth module refactoring</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Project Knowledge:</span></span>
<span class="line"><span>- [100%] Architecture follows MVC pattern</span></span>
<span class="line"><span>- [100%] Use &#39;npm run test&#39; for testing</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Relevant Memories:</span></span>
<span class="line"><span>- [85%] Previous fix for hydration error: use useEffect</span></span></code></pre></div></details><p>После просмотра этой информации Agent будет вести себя как старый сотрудник, который давно работает над этим проектом, а не как новый стажер.</p><hr><h2 id="механизм-триггеризации-по-ключевым-словам-nudge" tabindex="-1">Механизм триггеризации по ключевым словам (Nudge) <a class="header-anchor" href="#механизм-триггеризации-по-ключевым-словам-nudge" aria-label="Permalink to &quot;Механизм триггеризации по ключевым словам (Nudge)&quot;">​</a></h2><p>Помимо автоматического внедрения в начале, вы можете в любое время в процессе диалога &quot;пробудить&quot; функцию памяти.</p><p>Плагин имеет встроенный <strong>детектор ключевых слов</strong>. Пока ваше сообщение содержит определенный триггер, плагин отправит Agent &quot;невидимую подсказку&quot; (Nudge), заставляя его вызвать инструмент сохранения.</p><h3 id="ключевые-слова-по-умолчанию" tabindex="-1">Ключевые слова по умолчанию <a class="header-anchor" href="#ключевые-слова-по-умолчанию" aria-label="Permalink to &quot;Ключевые слова по умолчанию&quot;">​</a></h3><ul><li><code>remember</code></li><li><code>save this</code></li><li><code>don&#39;t forget</code></li><li><code>memorize</code></li><li><code>take note</code></li><li>... (см. конфигурацию исходного кода для большего)</li></ul><h3 id="пример-взаимодеиствия" tabindex="-1">Пример взаимодействия <a class="header-anchor" href="#пример-взаимодеиствия" aria-label="Permalink to &quot;Пример взаимодействия&quot;">​</a></h3><p><strong>Вы вводите</strong>:</p><blockquote><p>Формат ответа API здесь изменился, <strong>remember</strong> в дальнейшем используйте <code>data.result</code>, а не <code>data.payload</code>.</p></blockquote><p><strong>Плагин обнаруживает &quot;remember&quot;</strong>:</p><blockquote><p>(Внедрение подсказки в фоновом режиме): <code>[MEMORY TRIGGER DETECTED] The user wants you to remember something...</code></p></blockquote><p><strong>Реакция Agent</strong>:</p><blockquote><p>Принято. Я запомню это изменение. <em>(Фоновый вызов <code>supermemory.add</code> для сохранения памяти)</em></p></blockquote><hr><h2 id="глубокая-настроика" tabindex="-1">Глубокая настройка <a class="header-anchor" href="#глубокая-настроика" aria-label="Permalink to &quot;Глубокая настройка&quot;">​</a></h2><p>Вы можете изменить поведение внедрения, отредактировав <code>~/.config/opencode/supermemory.jsonc</code>.</p><h3 id="распространенные-параметры-конфигурации" tabindex="-1">Распространенные параметры конфигурации <a class="header-anchor" href="#распространенные-параметры-конфигурации" aria-label="Permalink to &quot;Распространенные параметры конфигурации&quot;">​</a></h3><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Внедрять ли профиль пользователя (по умолчанию true)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;injectProfile&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Сколько элементов памяти проекта внедрять каждый раз (по умолчанию 10)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Увеличение позволит Agent лучше узнать проект, но потребует больше токенов</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProjectMemories&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Сколько элементов профиля пользователя внедрять каждый раз (по умолчанию 5)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;maxProfileItems&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Пользовательские ключевые слова (поддерживаются регулярные выражения)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;keywordPatterns&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;запиши&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;сохранить навсегда&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Совет</p><p>После изменения конфигурации нужно перезапустить OpenCode или перезагрузить плагин, чтобы изменения вступили в силу.</p></div><hr><h2 id="частые-вопросы" tabindex="-1">Частые вопросы <a class="header-anchor" href="#частые-вопросы" aria-label="Permalink to &quot;Частые вопросы&quot;">​</a></h2><h3 id="q-внедренная-информация-занимает-много-токенов" tabindex="-1">Q: Внедренная информация занимает много токенов? <a class="header-anchor" href="#q-внедренная-информация-занимает-много-токенов" aria-label="Permalink to &quot;Q: Внедренная информация занимает много токенов?&quot;">​</a></h3><p><strong>A</strong>: Занимает часть, но обычно контролируется. При конфигурации по умолчанию (10 элементов памяти проекта + 5 элементов профиля) занимает около 500-1000 токенов. Для современных больших моделей (например, Claude 3.5 Sonnet) с контекстом 200k это лишь капля в море.</p><h3 id="q-я-сказал-remember-но-он-не-реагирует" tabindex="-1">Q: Я сказал &quot;remember&quot;, но он не реагирует? <a class="header-anchor" href="#q-я-сказал-remember-но-он-не-реагирует" aria-label="Permalink to &quot;Q: Я сказал &quot;remember&quot;, но он не реагирует?&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>Проверьте правильность написания (поддерживается сопоставление регулярных выражений).</li><li>Убедитесь, что API Key настроен правильно (если плагин не инициализирован, триггер не сработает).</li><li>Agent может решить игнорировать (хотя плагин принудительно подсказал, но Agent имеет окончательное право).</li></ol><h3 id="q-как-находятся-релевантные-памяти" tabindex="-1">Q: Как находятся &quot;релевантные памяти&quot;? <a class="header-anchor" href="#q-как-находятся-релевантные-памяти" aria-label="Permalink to &quot;Q: Как находятся &quot;релевантные памяти&quot;?&quot;">​</a></h3><p><strong>A</strong>: Они находятся на основе семантического поиска по содержанию <strong>вашего первого сообщения</strong>. Если в первом предложении вы сказали только &quot;Hi&quot;, возможно, не найдется полезной релевантной памяти, но &quot;знания о проекте&quot; и &quot;профиль пользователя&quot; все равно будут внедрены.</p><hr><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><ul><li><strong>Автоматическое внедрение</strong> срабатывает только при первом сообщении сессии.</li><li><strong>Трехмерная модель</strong> включает профиль пользователя, знания о проекте и релевантную память.</li><li><strong>Триггеризация по ключевым словам</strong> позволяет вам в любое время приказать Agent сохранить память.</li><li>Через <strong>файл конфигурации</strong> можно контролировать объем внедряемой информации.</li></ul><h2 id="предпросмотр-следующего-урока" tabindex="-1">Предпросмотр следующего урока <a class="header-anchor" href="#предпросмотр-следующего-урока" aria-label="Permalink to &quot;Предпросмотр следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../tools/">Набор инструментов: научить Agent запоминать</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как вручную использовать инструменты <code>add</code>, <code>search</code> и т. д.</li><li>Как просматривать и удалять неправильные памяти.</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы просмотреть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Логика триггера внедрения</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L125-L176" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>125-176</td></tr><tr><td>Обнаружение ключевых слов</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>Форматирование Prompt</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/context.ts#L14-L64" target="_blank" rel="noreferrer"><code>src/services/context.ts</code></a></td><td>14-64</td></tr><tr><td>Конфигурация по умолчанию</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L44-L54" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>44-54</td></tr></tbody></table><p><strong>Ключевые функции</strong>:</p><ul><li><code>formatContextForPrompt()</code>: Сборка текстового блока <code>[SUPERMEMORY]</code>.</li><li><code>detectMemoryKeyword()</code>: Регулярное сопоставление ключевых слов в сообщении пользователя.</li></ul></details><h2 id="предпросмотр-следующего-урока-1" tabindex="-1">Предпросмотр следующего урока <a class="header-anchor" href="#предпросмотр-следующего-урока-1" aria-label="Permalink to &quot;Предпросмотр следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../tools/">Набор инструментов: научить Agent запоминать</a></strong>.</p><p>Вы узнаете:</p><ul><li>Овладеть 5 основными режимами инструментов: <code>add</code>, <code>search</code>, <code>profile</code>, <code>list</code>, <code>forget</code></li><li>Как вручную вмешиваться и исправлять память Agent</li><li>Использовать естественный язык для триггерирования сохранения памяти</li></ul></blockquote>`,57)])])}const g=t(n,[["render",i]]);export{u as __pageData,g as default};
